-- The V11/V13 backfill only had keyword rules for a handful of categories
-- (water, tomato, rice, flour, ...) and sent everything else -- including all
-- the beverages (barley/malt drinks, fruit juices, sodas) -- to a single rice
-- fallback, so most drink products showed an identical rice photo. Re-match by
-- product name against a much broader keyword set that includes drink types,
-- and add real drink photos (juice, cola, soda, fanta).
--
-- Only touches rows still showing the over-used rice fallback image, so
-- correctly-matched demo photos and any user-uploaded photos are left alone.

UPDATE product_batches SET image_url = CASE
      WHEN lower(product_name) ~ 'sobolo|bissap|hibiscus|zobo|sorrel|roselle' THEN 'data:image/jpeg;base64,'
      WHEN lower(product_name) ~ 'water' THEN 'data:image/jpeg;base64,'
      WHEN lower(product_name) ~ 'cola' THEN 'data:image/jpeg;base64,'
      WHEN lower(product_name) ~ 'malt|malta|barley|guinness|stout' THEN 'data:image/jpeg;base64,'
      WHEN lower(product_name) ~ 'soda|fizz|\mpop\M|sprite|tonic|ginger beer' THEN 'data:image/jpeg;base64,'
      WHEN lower(product_name) ~ 'energy|fanta' THEN 'data:image/jpeg;base64,'
      WHEN lower(product_name) ~ 'juice|nectar|squash|smoothie|orange|pineapple|mango|guava|apple|citrus|fruit|passion|watermelon|tamarind|baobab|tigernut|lemon|grape|beetroot|coconut|moringa' THEN 'data:image/jpeg;base64,'
      WHEN lower(product_name) ~ 'drink|beverage|\msip\M|brew|\mtea\M' THEN 'data:image/jpeg;base64,'
      WHEN lower(product_name) ~ 'milk|soymilk|\msoy\M|dairy|yogurt|yoghurt' THEN 'data:image/jpeg;base64,'
      WHEN lower(product_name) ~ 'tomato' THEN 'data:image/jpeg;base64,'
      WHEN lower(product_name) ~ 'flour|wheat|semolina|cornmeal|grits|dough|banku|kenkey|fufu|garri|\mgari\M|porridge|koko|cereal' THEN 'data:image/jpeg;base64,'
      WHEN lower(product_name) ~ '\moil\M' THEN 'data:image/jpeg;base64,'
      WHEN lower(product_name) ~ 'biscuit|cookie|snack|cracker|\mcake\M|bread|pastry' THEN 'data:image/jpeg;base64,'
      WHEN lower(product_name) ~ 'groundnut|peanut|\mnut\M|cashew' THEN 'data:image/jpeg;base64,'
      WHEN lower(product_name) ~ 'spice|pepper|seasoning|curry|shito|\msalt\M|\msugar\M' THEN 'data:image/jpeg;base64,'
      WHEN lower(product_name) ~ 'rice' THEN 'data:image/jpeg;base64,'
      ELSE 'data:image/jpeg;base64,'
    END
WHERE image_url = 'data:image/jpeg;base64,' AND product_name IS NOT NULL;

UPDATE marketplace_posts SET image_url = CASE
      WHEN lower(title) ~ 'sobolo|bissap|hibiscus|zobo|sorrel|roselle' THEN 'data:image/jpeg;base64,'
      WHEN lower(title) ~ 'water' THEN 'data:image/jpeg;base64,'
      WHEN lower(title) ~ 'cola' THEN 'data:image/jpeg;base64,'
      WHEN lower(title) ~ 'malt|malta|barley|guinness|stout' THEN 'data:image/jpeg;base64,'
      WHEN lower(title) ~ 'soda|fizz|\mpop\M|sprite|tonic|ginger beer' THEN 'data:image/jpeg;base64,'
      WHEN lower(title) ~ 'energy|fanta' THEN 'data:image/jpeg;base64,'
      WHEN lower(title) ~ 'juice|nectar|squash|smoothie|orange|pineapple|mango|guava|apple|citrus|fruit|passion|watermelon|tamarind|baobab|tigernut|lemon|grape|beetroot|coconut|moringa' THEN 'data:image/jpeg;base64,'
      WHEN lower(title) ~ 'drink|beverage|\msip\M|brew|\mtea\M' THEN 'data:image/jpeg;base64,'
      WHEN lower(title) ~ 'milk|soymilk|\msoy\M|dairy|yogurt|yoghurt' THEN 'data:image/jpeg;base64,'
      WHEN lower(title) ~ 'tomato' THEN 'data:image/jpeg;base64,'
      WHEN lower(title) ~ 'flour|wheat|semolina|cornmeal|grits|dough|banku|kenkey|fufu|garri|\mgari\M|porridge|koko|cereal' THEN 'data:image/jpeg;base64,'
      WHEN lower(title) ~ '\moil\M' THEN 'data:image/jpeg;base64,'
      WHEN lower(title) ~ 'biscuit|cookie|snack|cracker|\mcake\M|bread|pastry' THEN 'data:image/jpeg;base64,'
      WHEN lower(title) ~ 'groundnut|peanut|\mnut\M|cashew' THEN 'data:image/jpeg;base64,'
      WHEN lower(title) ~ 'spice|pepper|seasoning|curry|shito|\msalt\M|\msugar\M' THEN 'data:image/jpeg;base64,'
      WHEN lower(title) ~ 'rice' THEN 'data:image/jpeg;base64,'
      ELSE 'data:image/jpeg;base64,'
    END
WHERE image_url = 'data:image/jpeg;base64,' AND title IS NOT NULL;
